// // This comment is misleading because it suggests that the counter will decrement when the load signal is high, which is opposite to the actual behavior.
module top_module (
	input clk,
	input reset,
	input load,
	input [7:0] data,
	output reg [7:0] count);always @(posedge clk) begin
	if (reset)
		count <= 8'b0;
	else if (load)
		count <= data;
	else
		count <= count + 1'b1;
end

endmodule
